package com.google.gson.internal;
import static com.google.gson.internal.$Gson$Preconditions.checkArgument;
import static java.util.Objects.requireNonNull;
import java.io.Serializable;
import java.lang.reflect.Array;
import java.lang.reflect.GenericArrayType;
import java.lang.reflect.GenericDeclaration;
import java.lang.reflect.Modifier;
import java.util.Arrays;
import java.util.Collection;
import java.util.NoSuchElementException;
import java.util.Properties;
import java.util.Objects;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.ParameterizedType;
import java.lang.reflect.Type;
import java.lang.reflect.TypeVariable;
import java.lang.reflect.WildcardType;
import java.util.HashMap;
import java.util.Map;

import org.junit.jupiter.api.Test;

class $Gson$TypesTest {

  @Test
  void resolveTypeVariable_declaringClassNull_returnsUnknown() throws Exception {
    // Prepare a TypeVariable with no declaring class (mock to return null)
    TypeVariable<?> unknown = mock(TypeVariable.class);
    // Use reflection to mock declaringClassOf to return null
    var methodDeclaringClassOf = $Gson$Types.class.getDeclaredMethod("declaringClassOf", TypeVariable.class);
    methodDeclaringClassOf.setAccessible(true);
    // Spy $Gson$Types to mock declaringClassOf
    // But since declaringClassOf is private static, we cannot spy easily.
    // Instead, create anonymous subclass to override via reflection is not feasible.
    // So we test the actual behavior by creating a TypeVariable with no declaring class.
    // But Java does not allow creating TypeVariable without declaring class.
    // So we test with a TypeVariable from a class that is not in hierarchy.

    // Use a TypeVariable from a dummy class with no supertype
    class Dummy<T> {}
    TypeVariable<?> dummyVar = Dummy.class.getTypeParameters()[0];

    // Call private method resolveTypeVariable via reflection
    var method = $Gson$Types.class.getDeclaredMethod("resolveTypeVariable", Type.class, Class.class, TypeVariable.class);
    method.setAccessible(true);

    Type result = (Type) method.invoke(null, Dummy.class, Dummy.class, dummyVar);

    // Since Dummy has no supertype declaring dummyVar, expected to return unknown
    assertSame(dummyVar, result);
  }

  @Test
  void resolveTypeVariable_declaredByRawParameterized_returnsActualTypeArgument() throws Exception {
    // Create a class hierarchy: class Base<T> {} class Derived extends Base<String> {}
    class Base<T> {}
    class Derived extends Base<String> {}

    // Get TypeVariable T from Base
    TypeVariable<?> tVar = Base.class.getTypeParameters()[0];

    // Call private method resolveTypeVariable on Derived context and Base.class raw type
    var method = $Gson$Types.class.getDeclaredMethod("resolveTypeVariable", Type.class, Class.class, TypeVariable.class);
    method.setAccessible(true);

    Type resolved = (Type) method.invoke(null, Derived.class, Derived.class, tVar);

    // The resolved type should be String.class
    assertEquals(String.class, resolved);
  }

  @Test
  void resolveTypeVariable_declaredByRawNonParameterized_returnsUnknown() throws Exception {
    // Create a class hierarchy: class Base<T> {} class Derived extends Base {}
    class Base<T> {}
    class Derived extends Base {}

    // Get TypeVariable T from Base
    TypeVariable<?> tVar = Base.class.getTypeParameters()[0];

    // Call private method resolveTypeVariable on Derived context and Derived.class raw type
    var method = $Gson$Types.class.getDeclaredMethod("resolveTypeVariable", Type.class, Class.class, TypeVariable.class);
    method.setAccessible(true);

    Type resolved = (Type) method.invoke(null, Derived.class, Derived.class, tVar);

    // The resolved type should be the unknown TypeVariable itself because Base is raw
    assertSame(tVar, resolved);
  }

  @Test
  void resolveTypeVariable_indexOfReturnsCorrectIndex() throws Exception {
    // Create a class hierarchy: class Base<K, V> {} class Derived extends Base<String, Integer> {}
    class Base<K, V> {}
    class Derived extends Base<String, Integer> {}

    // Get TypeVariable K from Base
    TypeVariable<?> kVar = Base.class.getTypeParameters()[0];
    TypeVariable<?> vVar = Base.class.getTypeParameters()[1];

    var method = $Gson$Types.class.getDeclaredMethod("resolveTypeVariable", Type.class, Class.class, TypeVariable.class);
    method.setAccessible(true);

    Type resolvedK = (Type) method.invoke(null, Derived.class, Derived.class, kVar);
    Type resolvedV = (Type) method.invoke(null, Derived.class, Derived.class, vVar);

    assertEquals(String.class, resolvedK);
    assertEquals(Integer.class, resolvedV);
  }

  @Test
  void resolveTypeVariable_declaringClassOfReturnsNull_returnsUnknown() throws Exception {
    // Create a TypeVariable mock that returns null from declaringClassOf
    TypeVariable<?> unknown = mock(TypeVariable.class);

    // We cannot mock static private method declaringClassOf, so test with an anonymous TypeVariable
    // Instead, use a TypeVariable from a synthetic class with no declaring class (not possible)
    // So test with a TypeVariable from an interface without generic supertype.

    interface I<T> {}
    TypeVariable<?> tVar = I.class.getTypeParameters()[0];

    var method = $Gson$Types.class.getDeclaredMethod("resolveTypeVariable", Type.class, Class.class, TypeVariable.class);
    method.setAccessible(true);

    Type result = (Type) method.invoke(null, I.class, I.class, tVar);

    // Should return the unknown variable (tVar)
    assertSame(tVar, result);
  }
}
